public void testCombineWithMultipleProperties() {
    ExtendedProperties props1 = new ExtendedProperties();
    props1.setProperty("key1", "\\\\server\\share");
    props1.setProperty("key2", "normalValue");
    props1.setProperty("key3", "\\t\\n\\r");

    ExtendedProperties props2 = new ExtendedProperties();
    props2.combine(props1);

    assertEquals("\\\\server\\share", props2.getProperty("key1"));
    assertEquals("normalValue", props2.getProperty("key2"));
    assertEquals("\\t\\n\\r", props2.getProperty("key3"));
}

public void testCombineOverwritesExistingProperties() {
    ExtendedProperties props1 = new ExtendedProperties();
    props1.setProperty("test", "\\\\path\\one");

    ExtendedProperties props2 = new ExtendedProperties();
    props2.setProperty("test", "oldValue");
    props2.setProperty("other", "keepThis");
    props2.combine(props1);

    assertEquals("\\\\path\\one", props2.getProperty("test"));
    assertEquals("keepThis", props2.getProperty("other"));
}

public void testCombineEmptyProperties() {
    ExtendedProperties props1 = new ExtendedProperties();

    ExtendedProperties props2 = new ExtendedProperties();
    props2.setProperty("existing", "value");
    props2.combine(props1);

    assertEquals("value", props2.getProperty("existing"));
    assertNull(props2.getProperty("nonexistent"));
}
